// firebase.js
import { initializeApp } from 'firebase/app';
import { getAuth, initializeAuth, getReactNativePersistence } from 'firebase/auth';
import ReactNativeAsyncStorage from '@react-native-async-storage/async-storage';
import { getDatabase } from 'firebase/database';
import { getStorage } from 'firebase/storage';

// Your web app's Firebase configuration
const firebaseConfig = {
  apiKey: "AIzaSyAiAhkPOOjiaoAiDBDuxX8yafq6TH8pFgw",
  authDomain: "car-rent-ad657.firebaseapp.com",
  databaseURL: "https://car-rent-ad657-default-rtdb.firebaseio.com",
  projectId: "car-rent-ad657",
  storageBucket: "car-rent-ad657.appspot.com",
  messagingSenderId: "974881637251",
  appId: "1:974881637251:web:b1d9916a55127b938becb6",
  measurementId: "G-661SRB3J4D"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);

// Initialize Auth with AsyncStorage
const auth = initializeAuth(app, {
  persistence: getReactNativePersistence(ReactNativeAsyncStorage)
});

// Initialize Realtime Database and Storage
const database = getDatabase(app);
const storage = getStorage(app);

export { auth, database, storage };
